import{_ as a,o as t,c as r,ae as i}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Creatives Manager","description":"","frontmatter":{"title":"Creatives Manager","slug":"creatives-manager"},"headers":[],"relativePath":"marketer-hub/creatives-manager.md","filePath":"marketer-hub/creatives-manager.md"}'),o={name:"marketer-hub/creatives-manager.md"};function s(n,e,l,h,c,d){return t(),r("div",null,[...e[0]||(e[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><a href="https://dashboard.branch.io/journeys/creatives/" target="_blank" rel="noreferrer">Creatives Manager</a> is a tab in the Branch Dashboard as part of Journeys. It allows you to look at all of your creatives (the banner, button, and/or interstitial) for easier management. A Journeys campaign consists of one or more creatives to drive your end-users from mobile web to app. You can now manage, create, edit, delete, or duplicate all of your creatives in one place.</p><h3 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h3><ol><li>Manage (build, edit, delete, duplicate) your creatives in one place.</li><li>Build a creative without creating a new Journeys campaign, allowing you to assign it to a Journey at a later date as needed.</li></ol><h2 id="managing-creatives" tabindex="-1">Managing Creatives <a class="header-anchor" href="#managing-creatives" aria-label="Permalink to &quot;Managing Creatives&quot;">​</a></h2><h3 id="templates" tabindex="-1">Templates <a class="header-anchor" href="#templates" aria-label="Permalink to &quot;Templates&quot;">​</a></h3><p>The <a href="https://dashboard.branch.io/journeys/creatives/templates" target="_blank" rel="noreferrer">Templates Tab</a> allows you to view all of the default Branch-provided creatives. These templates are used as a starting point for the creatives that you customize for your brand and use case. There are 20+ templates to choose from, and this is where you start to <a href="./creatives-manager.html#buildedit-creatives">build new creatives</a>.</p><h3 id="my-creatives" tabindex="-1">My Creatives <a class="header-anchor" href="#my-creatives" aria-label="Permalink to &quot;My Creatives&quot;">​</a></h3><p>The <a href="https://dashboard.branch.io/journeys/creatives/my-creatives" target="_blank" rel="noreferrer">My Creatives Tab</a> allows you to view all of the custom creatives that you or other team members have created. The creatives here can be <a href="./creatives-manager.html#buildedit-creatives">edited</a>, <a href="./creatives-manager.html#delete-creatives">deleted</a>, or <a href="./creatives-manager.html#duplicate-creatives">duplicated</a>. Some of the creatives here may already be assigned to a Journey, while others might not be assigned yet.</p><p>You can filter the creatives being shown by the Journeys campaigns they are assigned to.</p><h2 id="build-edit-creatives" tabindex="-1">Build/Edit Creatives <a class="header-anchor" href="#build-edit-creatives" aria-label="Permalink to &quot;Build/Edit Creatives&quot;">​</a></h2><p>A creative built through the Creatives Manager go through a slightly different process than if you are building it directly from creating a Journeys campaign.</p><h4 id="_1-select-a-template" tabindex="-1">1. Select a template <a class="header-anchor" href="#_1-select-a-template" aria-label="Permalink to &quot;1. Select a template&quot;">​</a></h4><p>Go to the <a href="https://dashboard.branch.io/journeys/creatives/templates" target="_blank" rel="noreferrer">Templates Tab</a> and select one of the 20+ templates as a base starting point for the creative you are looking to build.</p><h4 id="_2-customize-your-creative" tabindex="-1">2. Customize your creative <a class="header-anchor" href="#_2-customize-your-creative" aria-label="Permalink to &quot;2. Customize your creative&quot;">​</a></h4><p>You will need to name your unique creative and</p><h5 id="view-editor" tabindex="-1">View Editor <a class="header-anchor" href="#view-editor" aria-label="Permalink to &quot;View Editor&quot;">​</a></h5><p>The <em>View Editor Tab</em> allows you to utilize Branch&#39;s WYSIWYG editor to customize your creative. Just click on the element you want to edit, and the View Editor Tab will populate with fields you can input details about that element for you to customize (text, font, color, alignment, etc.).</p><p>Fill out the View Name. This should reflect the banner type and any additional information to help track performance when testing. <strong>Note:</strong> Try to stick to a naming convention so that you can easily find the creative later.</p><p>Customizable Elements (elements dependent on the selected template):</p><ul><li>App Icon</li><li>Title</li><li>Description</li><li><a href="./journeys-image-recommendations.html">Background</a></li><li>Content Position</li><li>Ratings Star Count</li><li>Reviews</li><li>Call to Action</li><li>Dismiss Journey Configuration</li></ul><h5 id="css-editor" tabindex="-1">CSS Editor <a class="header-anchor" href="#css-editor" aria-label="Permalink to &quot;CSS Editor&quot;">​</a></h5><p>You can utilize the <em>CSS Editor Tab</em> to customize your creative even further closer to your brand. This is for advanced users who have familiarity with CSS.</p><h5 id="page-placement" tabindex="-1">Page Placement <a class="header-anchor" href="#page-placement" aria-label="Permalink to &quot;Page Placement&quot;">​</a></h5><p>Use the <em>Page Placement Tab</em> to set the different styles of the way the banner/interstitial sits on the page.</p><p><strong>Note:</strong> Implement the <code>&lt;&gt;</code> element from the <em>Advanced Embed Options section</em> as the first child of your website&#39;s sticky top navigation bar to account for the height difference.</p><h5 id="dismissal-settings" tabindex="-1">Dismissal Settings <a class="header-anchor" href="#dismissal-settings" aria-label="Permalink to &quot;Dismissal Settings&quot;">​</a></h5><p>Use the <em>Dismissal Settings Tab</em> to adjust the behavior of your Journey when the user dismisses it. In some cases, rather than simply ignoring your Journeys, your users may want to dismiss them (by clicking either the <strong>“X”</strong> or the dismissal text on the Journey). In order to make sure that your users are having the best possible experience while also converting at the highest rate, you can adjust your Journeys’ dismissal settings while you’re setting up your creative.</p><ul><li>Dismissal Behavior: Choose what happens when a user dismisses a Journey. <strong>“Close Journey”</strong> will simply cause the Journey to close upon being dismissed; <strong>“Redirect to a web page”</strong> will cause the Journey to close and redirect to the webpage of your choice.</li><li>Dismissal Period: Use the dropdown to choose how long the Journey should be dismissed. Next, decide whether dismissing this Journey should cause only this Journey or all Journeys to be dismissed for the chosen period.</li></ul><p><strong>Note:</strong> Dismissal Settings is only adjustable if the creative you are building/editing is already assigned to a Journeys campaign.</p><h4 id="_3-save-your-creative" tabindex="-1">3. Save your creative <a class="header-anchor" href="#_3-save-your-creative" aria-label="Permalink to &quot;3. Save your creative&quot;">​</a></h4><p>Your finished creative should appear in the <a href="https://dashboard.branch.io/journeys/creatives/my-creatives" target="_blank" rel="noreferrer">My Creatives Tab</a>.</p><h2 id="delete-creatives" tabindex="-1">Delete Creatives <a class="header-anchor" href="#delete-creatives" aria-label="Permalink to &quot;Delete Creatives&quot;">​</a></h2><p>When deleting a creative from the <a href="https://dashboard.branch.io/journeys/creatives/my-creatives" target="_blank" rel="noreferrer">My Creatives Tab</a>, you will be prompted with one of two messages:</p><h4 id="deleting-an-assigned-creative" tabindex="-1">Deleting an Assigned Creative <a class="header-anchor" href="#deleting-an-assigned-creative" aria-label="Permalink to &quot;Deleting an Assigned Creative&quot;">​</a></h4><p><em>[Image: 757]</em></p><p>Attempting to delete will have an impact on a created Journey, so clicking <strong>&quot;Yes, Continue&quot;</strong> will redirect you to managing that Journey. You will need to unassign the creative from that Journey before you are able to delete it.</p><h4 id="deleting-an-unassigned-creative" tabindex="-1">Deleting an Unassigned Creative <a class="header-anchor" href="#deleting-an-unassigned-creative" aria-label="Permalink to &quot;Deleting an Unassigned Creative&quot;">​</a></h4><p><em>[Image: 760]</em></p><p>Click <strong>&quot;Yes, Delete&quot;</strong> to permanently delete the creative.</p><h2 id="duplicate-creatives" tabindex="-1">Duplicate Creatives <a class="header-anchor" href="#duplicate-creatives" aria-label="Permalink to &quot;Duplicate Creatives&quot;">​</a></h2><p>Duplicating a creative from the <a href="https://dashboard.branch.io/journeys/creatives/my-creatives" target="_blank" rel="noreferrer">My Creatives Tab</a> will make an exact copy of the selected creative and redirect you to <a href="./creatives-manager.html#buildedit-creatives">edit the duplicate creative</a>.</p>',42)])])}const p=a(o,[["render",s]]);export{m as __pageData,p as default};
